// frontend/src/pages/AdminPage.js
import { useState, useEffect } from 'react';
import API from '../api/axios';

const AdminPage = () => {
  const [users, setUsers] = useState([]);
  const [posts, setPosts] = useState([]);
  const [tab, setTab] = useState('users');

  useEffect(() => {
    API.get('/admin/users').then(res => setUsers(res.data));
    API.get('/admin/posts').then(res => setPosts(res.data));
  }, []);

  const toggleStatus = async (id) => {
    const { data } = await API.put(`/admin/users/${id}/status`);
    setUsers(users.map(u => (u._id === id ? data.user : u)));
  };

  const removePost = async (id) => {
    await API.put(`/admin/posts/${id}/remove`);
    setPosts(posts.map(p => (p._id === id ? { ...p, status: 'removed' } : p)));
  };

 const isDark = document.body.classList.contains("dark-mode");

const styles = {
  page: {
    backgroundColor: isDark ? '#560032' : '#FAE8ED',
    minHeight: '100vh',
    padding: '30px',
    fontFamily: 'Georgia, serif',
    color: isDark ? '#f5d6e6' : 'rgb(12, 75, 52)',
  },

  container: {
    maxWidth: '1000px',
    margin: '0 auto',
    backgroundColor: isDark ? '#2b1b2b' : '#f7c6d9',
    padding: '30px',
    borderRadius: '20px',
    boxShadow: isDark
      ? '0 10px 30px rgba(0,0,0,0.6)'
      : '0 10px 30px rgba(0,0,0,0.1)',
  },

  heading: {
    fontSize: '36px',
    textAlign: 'center',
    marginBottom: '20px',
    fontWeight: 'bold',
  },

  tabs: {
    display: 'flex',
    justifyContent: 'center',
    gap: '10px',
    marginBottom: '20px',
  },

  tabButton: {
    padding: '10px 25px',
    borderRadius: '50px',
    border: 'none',
    cursor: 'pointer',
    fontWeight: 'bold',
    backgroundColor: isDark ? '#3a253a' : '#ffffff',
    color: isDark ? '#fff' : 'rgb(12, 75, 52)',
    transition: '0.3s',
  },

  activeTab: {
    backgroundColor: isDark ? '#ff4d6d' : 'rgb(12, 75, 52)',
    color: '#fff',
  },

  table: {
    width: '100%',
    borderCollapse: 'collapse',
    marginTop: '10px',
    backgroundColor: isDark ? '#3a253a' : '#ffffff',
    borderRadius: '15px',
    overflow: 'hidden',
  },

  th: {
    padding: '15px',
    backgroundColor: isDark ? '#4a2e4a' : 'rgb(12, 75, 52)',
    color: '#fff',
    textAlign: 'left',
  },

  td: {
    padding: '12px',
    borderBottom: isDark ? '1px solid #4a2e4a' : '1px solid #eee',
  },

  status: {
    padding: '5px 12px',
    borderRadius: '20px',
    fontSize: '12px',
    fontWeight: 'bold',
    textTransform: 'capitalize',
  },

  activeStatus: {
    backgroundColor: isDark ? '#3d6b52' : '#d4edda',
    color: isDark ? '#d4edda' : '#155724',
  },

  inactiveStatus: {
    backgroundColor: isDark ? '#6b3d3d' : '#f8d7da',
    color: isDark ? '#ffd6d6' : '#721c24',
  },

  removedStatus: {
    backgroundColor: isDark ? '#555' : '#eee',
    color: isDark ? '#ddd' : '#555',
  },

  button: {
    padding: '8px 15px',
    borderRadius: '20px',
    border: 'none',
    cursor: 'pointer',
    fontWeight: 'bold',
    transition: '0.3s',
  },

  dangerBtn: {
    backgroundColor: '#ff4d6d',
    color: '#fff',
  },

  successBtn: {
    backgroundColor: isDark ? '#ff7aa2' : 'rgb(12, 75, 52)',
    color: '#fff',
  },
};

  const getStatusStyle = (status) => {
    if (status === 'active' || status === 'published')
      return { ...styles.status, ...styles.activeStatus };
    if (status === 'inactive')
      return { ...styles.status, ...styles.inactiveStatus };
    return { ...styles.status, ...styles.removedStatus };
  };

  return (
    <div style={styles.page}>
      <div style={styles.container}>
        <h2 style={styles.heading}>Admin Dashboard</h2>

        {/* Tabs */}
        <div style={styles.tabs}>
          <button
            onClick={() => setTab('users')}
            style={{
              ...styles.tabButton,
              ...(tab === 'users' ? styles.activeTab : {}),
            }}
          >
            Members ({users.length})
          </button>

          <button
            onClick={() => setTab('posts')}
            style={{
              ...styles.tabButton,
              ...(tab === 'posts' ? styles.activeTab : {}),
            }}
          >
            All Posts ({posts.length})
          </button>
        </div>

        {/* Users Table */}
        {tab === 'users' && (
          <table style={styles.table}>
            <thead>
              <tr>
                <th style={styles.th}>Name</th>
                <th style={styles.th}>Email</th>
                <th style={styles.th}>Status</th>
                <th style={styles.th}>Action</th>
              </tr>
            </thead>
            <tbody>
              {users.map(u => (
                <tr key={u._id}>
                  <td style={styles.td}>{u.name}</td>
                  <td style={styles.td}>{u.email}</td>
                  <td style={styles.td}>
                    <span style={getStatusStyle(u.status)}>
                      {u.status}
                    </span>
                  </td>
                  <td style={styles.td}>
                    <button
                      onClick={() => toggleStatus(u._id)}
                      style={{
                        ...styles.button,
                        ...(u.status === 'active'
                          ? styles.dangerBtn
                          : styles.successBtn),
                      }}
                    >
                      {u.status === 'active' ? 'Deactivate' : 'Activate'}
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        )}

        {/* Posts Table */}
        {tab === 'posts' && (
          <table style={styles.table}>
            <thead>
              <tr>
                <th style={styles.th}>Title</th>
                <th style={styles.th}>Author</th>
                <th style={styles.th}>Status</th>
                <th style={styles.th}>Action</th>
              </tr>
            </thead>
            <tbody>
              {posts.map(p => (
                <tr key={p._id}>
                  <td style={styles.td}>{p.title}</td>
                  <td style={styles.td}>{p.author?.name}</td>
                  <td style={styles.td}>
                    <span style={getStatusStyle(p.status)}>
                      {p.status}
                    </span>
                  </td>
                  <td style={styles.td}>
                    {p.status === 'published' && (
                      <button
                        style={{ ...styles.button, ...styles.dangerBtn }}
                        onClick={() => removePost(p._id)}
                      >
                        Remove
                      </button>
                    )}
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        )}
      </div>
    </div>
  );
};

export default AdminPage;
